\begin{lemma}[Tower-cancellation equivalence for K\"ahler modules under localization]
  \label{lem:kaehler_quotient_localization_iso}
  \lean{AlgebraicGeometry.Scheme.kaehler_quotient_localization_iso}
  \uses{lem:kaehler_localization_subsingleton}
  Let $A \to L$ be a localization (in the sense of \texttt{IsLocalization}), and let $L \to B$ be a ring map forming a scalar tower $A \to L \to B$. Then the canonical $B$-linear map $\Omega_{B/A} \to \Omega_{B/L}$ induced by the tower is a $B$-linear equivalence.
\end{lemma}

\begin{proof}
  \uses{lem:kaehler_localization_subsingleton}
  The second fundamental exact sequence of K\"ahler differentials reads
  \[
    B \otimes_{L} \Omega_{L/A} \;\longrightarrow\; \Omega_{B/A} \;\twoheadrightarrow\; \Omega_{B/L} \;\longrightarrow\; 0.
  \]
  By Lemma~\ref{lem:kaehler_localization_subsingleton}, the left term vanishes (since $\Omega_{L/A}$ is subsingleton and tensoring against it gives the zero module). Therefore the right surjection has zero kernel and is a $B$-linear equivalence. The Mathlib closure pieces are \texttt{KaehlerDifferential.exact\_mapBaseChange\_map}~\texttt{[verified]} (the exact sequence above) and \texttt{KaehlerDifferential.map\_surjective}~\texttt{[verified]} (the right-hand surjection), both in \texttt{Mathlib.RingTheory.Kaehler.Basic}; the project-side declaration packages these into a \texttt{LinearEquiv} via \texttt{LinearEquiv.ofBijective}. This is the most extractable Mathlib contribution candidate of milestone~M1: a clean generalisation of \texttt{KaehlerDifferential.tensorKaehlerEquivOfFormallyEtale} to the ``only the lower step is formally unramified'' case, candidate name \texttt{KaehlerDifferential.equivOfFormallyUnramified}.
\end{proof}

